void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("deGraf_1");			link.l1 = StringFromKey("deGraf_2");			link.l1.go = "exit";			NextDiag.TempNode = "1";		break;		case "1":			dialog.text = StringFromKey("deGraf_3");			link.l1 = StringFromKey("deGraf_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("deGraf_5");			link.l1 = StringFromKey("deGraf_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("deGraf_7");			link.l1 = StringFromKey("deGraf_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("deGraf_9");			link.l1 = StringFromKey("deGraf_10");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("deGraf_11");			link.l1 = StringFromKey("deGraf_12");			link.l1.go = "exit";			AddDialogExitQuest("FL9_s54");		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}